| MCP:LxgNc1 | const Mock = require('mockjs')
| MCP:LxgNc1 | const { param2Obj } = require('./utils')
| MCP:LxgNc1 | 
| MCP:LxgNc1 | const user = require('./user')
| MCP:LxgNc1 | const table = require('./table')
| MCP:LxgNc1 | 
| MCP:LxgNc1 | const mocks = [...user, ...table]
| MCP:LxgNc1 | 
| MCP:LxgNc1 | // for front mock
| MCP:LxgNc1 | // please use it cautiously, it will redefine XMLHttpRequest,
| MCP:LxgNc1 | // which will cause many of your third-party libraries to be invalidated(like progress event).
| MCP:LxgNc1 | function mockXHR() {
| MCP:LxgNc1 |   // mock patch
| MCP:LxgNc1 |   // https://github.com/nuysoft/Mock/issues/300
| MCP:LxgNc1 |   Mock.XHR.prototype.proxy_send = Mock.XHR.prototype.send
| MCP:LxgNc1 |   Mock.XHR.prototype.send = function () {
| MCP:LxgNc1 |     if (this.custom.xhr) {
| MCP:LxgNc1 |       this.custom.xhr.withCredentials = this.withCredentials || false
| MCP:LxgNc1 | 
| MCP:LxgNc1 |       if (this.responseType) {
| MCP:LxgNc1 |         this.custom.xhr.responseType = this.responseType
| MCP:LxgNc1 |       }
| MCP:LxgNc1 |     }
| MCP:LxgNc1 |     this.proxy_send(...arguments)
| MCP:LxgNc1 |   }
| MCP:LxgNc1 | 
| MCP:LxgNc1 |   function XHR2ExpressReqWrap(respond) {
| MCP:LxgNc1 |     return function (options) {
| MCP:LxgNc1 |       let result = null
| MCP:LxgNc1 |       if (respond instanceof Function) {
| MCP:LxgNc1 |         const { body, type, url } = options
| MCP:LxgNc1 |         // https://expressjs.com/en/4x/api.html#req
| MCP:LxgNc1 |         result = respond({
| MCP:LxgNc1 |           method: type,
| MCP:LxgNc1 |           body: JSON.parse(body),
| MCP:LxgNc1 |           query: param2Obj(url),
| MCP:LxgNc1 |         })
| MCP:LxgNc1 |       } else {
| MCP:LxgNc1 |         result = respond
| MCP:LxgNc1 |       }
| MCP:LxgNc1 |       return Mock.mock(result)
| MCP:LxgNc1 |     }
| MCP:LxgNc1 |   }
| MCP:LxgNc1 | 
| MCP:LxgNc1 |   for (const i of mocks) {
| MCP:LxgNc1 |     Mock.mock(
| MCP:LxgNc1 |       new RegExp(i.url),
| MCP:LxgNc1 |       i.type || 'get',
| MCP:LxgNc1 |       XHR2ExpressReqWrap(i.response)
| MCP:LxgNc1 |     )
| MCP:LxgNc1 |   }
| MCP:LxgNc1 | }
| MCP:LxgNc1 | 
| MCP:LxgNc1 | module.exports = {
| MCP:LxgNc1 |   mocks,
| MCP:LxgNc1 |   mockXHR,
| MCP:LxgNc1 | }

